def plot_cc_hvg(adata: sc.AnnData) -> None:
    
    bioreport.log("CC genes coloured:")
    adata.var["cc_genes"] = adata.var_names.str.upper().isin({gene.upper() for gene in CC_GENES})
    
    sns.scatterplot(data=adata.var, x="means", y="dispersions_norm", hue="cc_genes", s=5)
    bioreport.figure("cc_genes_hvg")
 

